const items = $input.all();

function trim(v) {
  return String(v ?? '').trim();
}

function normalizePhone(v) {
  const raw = trim(v).replace(/[^\d+]/g, '');
  if (!raw) return '';
  const canonical = raw.startsWith('+62') ? `62${raw.slice(3)}` : raw;
  return canonical.startsWith('0') ? `62${canonical.slice(1)}` : canonical;
}

return items.map((item) => {
  const payload = item.json || {};
  const to = normalizePhone(payload.to);
  const message = trim(payload.message);

  if (!to) throw new Error('Payload invalid: field "to" wajib diisi.');
  if (!message) throw new Error('Payload invalid: field "message" wajib diisi.');

  return {
    json: {
      to,
      chatId: `${to}@c.us`,
      message,
      eticket_no: trim(payload.eticket_no) || null,
      student_name: trim(payload.student_name) || null,
      source: trim(payload.source) || 'ppdb_register',
      received_at: new Date().toISOString()
    }
  };
});

const items = $input.all();

const endpointBase = String($env.N8N_WAHA_BASE_URL || 'https://waha.devlike.pro').trim().replace(/\/+$/, '');
const endpoint = `${endpointBase}/api/sendText`;
const token = String($env.N8N_WAHA_API_KEY || '').trim();
const session = String($env.N8N_WAHA_SESSION || 'default').trim() || 'default';

const out = [];
for (const { json } of items) {
  try {
    const response = await fetch(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { 'X-Api-Key': token } : {})
      },
      body: JSON.stringify({
        session,
        chatId: json.chatId,
        text: json.message
      })
    });

    const text = await response.text().catch(() => '');
    out.push({
      json: {
        ...json,
        sent: response.ok,
        provider: 'waha',
        reason: response.ok ? 'sent' : `http_${response.status}`,
        gateway_status: response.status,
        gateway_response: text ? text.slice(0, 500) : null
      }
    });
  } catch (error) {
    out.push({
      json: {
        ...json,
        sent: false,
        provider: 'waha',
        reason: 'network_error',
        gateway_status: 0,
        gateway_response: String(error?.message || error || 'unknown_error').slice(0, 500)
      }
    });
  }
}

return out;
